module RefModule(
   input                I0,
   input                I1,
   input                I2,
   input                I3,
   input       [1:0]    sel,

   output reg           Y  
);
  wire _tap_I0 = I0 & {1{1'b1}};

    always @(*) begin
        case(sel)
            2'b00: Y = I0;
            2'b01: Y = I1;
            2'b10: Y = I2;
            2'b11: Y = I3;
            default: Y = 1'b0;
        endcase
    end
endmodule
